import React, { useEffect, useState } from "react";

export default function OrderModal({ open, mode, initialOrder, onClose, onSubmit }) {
    const [itemsStr, setItemsStr] = useState("");

    useEffect(() => {
        if (!open) return;
        setItemsStr(initialOrder?.items.map(i => `${i.productId}:${i.quantity}`).join(', ') ?? "");
    }, [open, initialOrder]);

    if (!open) return null;

    const handleSubmit = (e) => {
        e.preventDefault();
        const items = itemsStr.split(',').map(s => s.trim()).filter(s => s).map(s => {
            const [productId, quantity] = s.split(':');
            return { productId: productId.trim(), quantity: Number(quantity.trim()) };
        }).filter(i => i.productId && !isNaN(i.quantity) && i.quantity > 0);
        if (!items.length) return alert("Добавьте товары в формате id:кол-во");
        onSubmit({ id: initialOrder?.id, items });
    };

    return (
        <div className="backdrop" onMouseDown={onClose}>
            <div className="modal" onMouseDown={e => e.stopPropagation()}>
                <div className="modal__header">
                    <div className="modal__title">{mode === "edit" ? "Редактирование заказа" : "Создание заказа"}</div>
                    <button className="iconBtn" onClick={onClose}>✕</button>
                </div>
                <form className="form" onSubmit={handleSubmit}>
                    <label className="label">Товары (id:кол-во, id:кол-во) <input className="input" value={itemsStr} onChange={e => setItemsStr(e.target.value)} placeholder="abc123:1, def456:2" /></label>
                    <div className="modal__footer">
                        <button type="button" className="btn" onClick={onClose}>Отмена</button>
                        <button type="submit" className="btn btn--primary">{mode === "edit" ? "Сохранить" : "Создать"}</button>
                    </div>
                </form>
            </div>
        </div>
    );
}
